import os
import psycopg2
import psycopg2.extras

DEFAULT_DSN = os.getenv("DATABASE_URL", "dbname=mydb user=myuser password=mypassword host=localhost")

def get_connection(dsn: str | None = None) -> psycopg2.extensions.connection:
    return psycopg2.connect(dsn or DEFAULT_DSN)

def search_users(
    username: str | None = None,
    email: str | None = None,
    role: str | None = None,
    status: str | None = None,
    limit: int = 100,
    conn: psycopg2.extensions.connection | None = None,
) -> list[dict]:
    close_after = False
    if conn is None:
        conn = get_connection()
        close_after = True

    query = "SELECT id, username, email, role, status, created_at FROM users"
    conditions = []
    params: list = []

    if username:
        conditions.append("username ILIKE %s")
        params.append(f"%{username}%")
    if email:
        conditions.append("email ILIKE %s")
        params.append(f"%{email}%")
    if role:
        conditions.append("role = %s")
        params.append(role)
    if status:
        conditions.append("status = %s")
        params.append(status)

    if conditions:
        query += " WHERE " + " AND ".join(conditions)

    query += " ORDER BY username LIMIT %s"
